```javascript
function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    let maxW = 0;
    for (let e of edges) {
        if (e[2] > maxW) maxW = e[2];
    }
    let low = 0, high = maxW;
    let answer = maxW;

    function countComponents(X) {
        let parent = new Array(n).fill(0).map((_, i) => i);
        let rank = new Array(n).fill(0);

        function find(u) {
            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }

        function union(u, v) {
            let u_root = find(u);
            let v_root = find(v);
            if (u_root === v_root) return;
            if (rank[u_root] < rank[v_root]) {
                parent[u_root] = v_root;
            } else {
                parent[v_root] = u_root;
                if (rank[u_root] === rank[v_root]) {
                    rank[u_root]++;
                }
            }
        }

        for (let edge of edges) {
            if (edge[2] <= X) {
                union(edge[0], edge[1]);
            }
        }

        let roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let components = countComponents(mid);
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
